Code.Terraform:
```hcl
# クラスターで使用されている Redshift パラメーターグループで require_ssl を true に設定します
resource "aws_redshift_parameter_group" "<example_resource_name>" {
  name   = "<example_resource_name>"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"   # CRITICAL: クライアント接続に TLS を強制します
    value = "true"          # CRITICAL: SSL 要件を有効にします
  }
}
```
